import java.util.*;

public class DijkstraAlgorithm {
    static class Edge {
        int destination;
        int weight;
        Edge(int dest, int w) {
            destination = dest;
            weight = w;
        }
    }

    static class Node implements Comparable<Node> {
        int vertex;
        int distance;
        Node(int v, int d) {
            vertex = v;
            distance = d;
        }
        public int compareTo(Node other) {
            return this.distance - other.distance;
        }
    }

    public static void dijkstra(List<List<Edge>> graph, int source) {
        int V = graph.size();
        int[] dist = new int[V];
        int[] parent = new int[V];
        boolean[] visited = new boolean[V];

        Arrays.fill(dist, Integer.MAX_VALUE);
        Arrays.fill(parent, -1);
        dist[source] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(source, 0));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            int u = current.vertex;

            if (visited[u]) continue;
            visited[u] = true;

            for (Edge edge : graph.get(u)) {
                int v = edge.destination;
                int weight = edge.weight;

                if (!visited[v] && dist[u] != Integer.MAX_VALUE) {
                    int newDist = dist[u] + weight;
                    if (newDist < dist[v]) {
                        dist[v] = newDist;
                        parent[v] = u;
                        pq.add(new Node(v, newDist));
                    }
                }
            }
        }

        System.out.println("Shortest distances from source " + source + ":");
        for (int i = 0; i < V; i++) {
            System.out.println("To " + i + ": " + dist[i]);
        }
    }

    public static void main(String[] args) {
        int V = 6;
        List<List<Edge>> graph = new ArrayList<>();
        for (int i = 0; i < V; i++) graph.add(new ArrayList<>());

        // Add edges (undirected)
        addEdge(graph, 0, 1, 4); addEdge(graph, 1, 0, 4);
        addEdge(graph, 0, 2, 2); addEdge(graph, 2, 0, 2);
        addEdge(graph, 1, 2, 1); addEdge(graph, 2, 1, 1);
        addEdge(graph, 1, 3, 5); addEdge(graph, 3, 1, 5);
        addEdge(graph, 2, 3, 8); addEdge(graph, 3, 2, 8);
        addEdge(graph, 3, 4, 2); addEdge(graph, 4, 3, 2);
        addEdge(graph, 4, 5, 3); addEdge(graph, 5, 4, 3);

        dijkstra(graph, 0);
    }

    static void addEdge(List<List<Edge>> graph, int u, int v, int w) {
        graph.get(u).add(new Edge(v, w));
    }
}
